  sayHello(): void;
}

class Coffee implements Drink {
  sayHello(): void {
    console.log("Hello, I'm coffee!");
  }
}

class Tea implements Drink {
  sayHello(): void {
    console.log("Hello, I'm tea!");
  }
}

